const { withAppBuildGradle } = require("expo/config-plugins");

const FINALIZE_DSL_MARKER =
  "// @generated by with-android-locale-resource-qualifiers";

function toAndroidResourceQualifier(locale) {
  let canonicalLocale;

  try {
    canonicalLocale = new Intl.Locale(locale).toString();
  } catch {
    throw new Error(`Invalid BCP-47 locale: ${JSON.stringify(locale)}.`);
  }

  return `b+${canonicalLocale.replaceAll("-", "+")}`;
}

module.exports = function withAndroidLocaleResourceQualifiers(config, options) {
  const supportedLocales = options?.supportedLocales;
  if (
    !Array.isArray(supportedLocales) ||
    supportedLocales.length === 0 ||
    supportedLocales.some((locale) => typeof locale !== "string")
  ) {
    throw new Error(
      "with-android-locale-resource-qualifiers requires supportedLocales.",
    );
  }

  const rawLocales = `[${supportedLocales
    .map((locale) => JSON.stringify(locale))
    .join(", ")}]`;
  const convertedLocales = `[${supportedLocales
    .map((locale) => JSON.stringify(toAndroidResourceQualifier(locale)))
    .join(", ")}]`;
  const originalConfiguration = `resourceConfigurations += ${rawLocales}`;
  const convertedConfiguration = `resourceConfigurations += ${convertedLocales}`;

  return withAppBuildGradle(config, (config) => {
    if (config.modResults.language !== "groovy") {
      throw new Error(
        "Android locale resource qualifier conversion requires Groovy build.gradle.",
      );
    }

    if (config.modResults.contents.includes(originalConfiguration)) {
      // expo-localization 17.0.9 writes BCP-47 tags directly to AAPT's resource
      // filter. Convert them to Android qualifiers while keeping locales_config.xml
      // in the BCP-47 format required by Android's per-app language settings.
      config.modResults.contents = config.modResults.contents.replaceAll(
        originalConfiguration,
        convertedConfiguration,
      );
    }

    if (!config.modResults.contents.includes(FINALIZE_DSL_MARKER)) {
      config.modResults.contents += `

${FINALIZE_DSL_MARKER}
androidComponents {
    finalizeDsl { extension ->
        extension.defaultConfig.resourceConfigurations.removeAll(${rawLocales})
        extension.defaultConfig.resourceConfigurations.addAll(${convertedLocales})
    }
}
`;
    }

    return config;
  });
};
